import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  Archive,
  Check,
  Copy,
  ExternalLink,
  Info,
  Pencil,
  Plus,
  RotateCcw,
  X,
  AlertTriangle,
} from "lucide-react";
import { PageShell } from "@/components/orderly/PageShell";
import { Modal } from "@/components/orderly/Modal";
import { fetchPublicFutures } from "@/services/orderly";
import { signedAdminRequest, MissingApiKeyError } from "@/utils/adminKeyAuth";

type OrderEnumStatus = "active" | "archived";

interface OrderEnum {
  enum_id: string;
  name: string;
  description: string;
  status: OrderEnumStatus;
  default_fee_rate: number;
  pair_overrides: Record<string, number>;
  created_time?: number;
  updated_time?: number;
}

interface EnumUsageStats {
  enum_id: string;
  orders_count: number;
  volume_usd: number;
  fees_collected_usd: number;
}

interface OrderEnumApiRow extends OrderEnum {
  usage_stats?: {
    total_orders?: number;
    total_volume?: string;
    total_fees_collected?: string;
  };
}

type OrderEnumListResponse =
  | OrderEnumApiRow[]
  | { success?: boolean; data?: OrderEnumApiRow[]; message?: string };
type OrderEnumMutationResponse = {
  success?: boolean;
  data?: OrderEnumApiRow;
  message?: string;
};

const ORDER_ENUM_API = "/v1/broker/order_enum";
const ORDER_ENUMS_LIST_API = "/v1/broker/order_enums";
const MAX_ACTIVE_ENUMS = 10;
const MAX_FEE_RATE = 0.01;
const MIN_FEE_RATE = 0.00001;
const MAX_ENUM_ID_LENGTH = 31;
const ENUM_ID_REGEX = /^[A-Z][A-Z0-9_]*$/;

function normalizeRows(response: OrderEnumListResponse): OrderEnumApiRow[] {
  if (Array.isArray(response)) return response;
  return response.data || [];
}

function transformApiEnum(row: OrderEnumApiRow): OrderEnum {
  return {
    enum_id: row.enum_id,
    name: row.name,
    description: row.description || "",
    status: row.status,
    default_fee_rate: row.default_fee_rate ?? 0,
    pair_overrides: row.pair_overrides ?? {},
    created_time: row.created_time,
    updated_time: row.updated_time,
  };
}

function getEnumStats(row: OrderEnumApiRow): EnumUsageStats | undefined {
  if (!row.usage_stats) return undefined;
  return {
    enum_id: row.enum_id,
    orders_count: row.usage_stats.total_orders || 0,
    volume_usd: Number.parseFloat(row.usage_stats.total_volume || "0"),
    fees_collected_usd: Number.parseFloat(
      row.usage_stats.total_fees_collected || "0"
    ),
  };
}

function validateEnumId(enumId: string): string | null {
  if (!enumId.trim()) return "Tag ID is required";
  if (enumId.length > MAX_ENUM_ID_LENGTH)
    return `Tag ID must be at most ${MAX_ENUM_ID_LENGTH} characters`;
  if (!ENUM_ID_REGEX.test(enumId))
    return "Tag ID must be uppercase alphanumeric and underscores only, starting with a letter";
  return null;
}

function validateFeeRate(rate: number): string | null {
  if (Number.isNaN(rate)) return "Fee rate is required";
  if (rate < 0) return "Fee rate cannot be negative";
  if (rate < MIN_FEE_RATE) return "Fee rate must be at least 0.001%";
  if (rate > MAX_FEE_RATE) return "Fee rate must be at most 1.00%";
  const decimalPart =
    (Math.round(rate * 1e8) / 1e8).toString().split(".")[1] || "";
  if (decimalPart.length > 5)
    return "Fee rate must use 3 decimal places or fewer in percent, e.g. 0.001%";
  return null;
}

function validatePairOverride(rate: number): string | null {
  if (Number.isNaN(rate)) return "Symbol-specific fee is required";
  if (rate < 0) return "Pair override fee cannot be negative";
  if (rate > MAX_FEE_RATE) return "Pair override fee must be at most 1.00%";
  const decimalPart =
    (Math.round(rate * 1e8) / 1e8).toString().split(".")[1] || "";
  if (decimalPart.length > 5)
    return "Symbol-specific fee must use 3 decimal places or fewer in percent, e.g. 0.001%";
  return null;
}

function parsePercentInput(value: string): number {
  return Number.parseFloat(value) / 100;
}

function sanitizePercentInput(value: string): string {
  const stripped = value.replace(/[^\d.]/g, "");
  const parts = stripped.split(".");
  const normalized =
    parts.length > 2 ? parts[0] + "." + parts.slice(1).join("") : stripped;
  const [whole, fraction] = normalized.split(".");
  return fraction === undefined ? whole : `${whole}.${fraction.slice(0, 3)}`;
}

function formatFeeRate(rate: number): string {
  return `${(rate * 100).toFixed(3)}%`;
}

function formatNumber(num: number): string {
  if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(2)}B`;
  if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(2)}M`;
  if (num >= 1_000) return `${(num / 1_000).toFixed(2)}K`;
  return num.toFixed(0);
}

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

async function copyText(text: string) {
  await navigator.clipboard.writeText(text);
}

export default function OrderEnumPage() {
  const [enums, setEnums] = useState<OrderEnum[]>([]);
  const [statsMap, setStatsMap] = useState<Record<string, EnumUsageStats>>({});
  const [availableSymbols, setAvailableSymbols] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [symbolsLoading, setSymbolsLoading] = useState(true);
  const [toast, setToast] = useState<{
    message: string;
    type: "success" | "error";
  } | null>(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editEnum, setEditEnum] = useState<OrderEnum | null>(null);
  const [archiveTarget, setArchiveTarget] = useState<OrderEnum | null>(null);
  const [isArchiveAction, setIsArchiveAction] = useState(true);

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const response = await signedAdminRequest<OrderEnumListResponse>({
        endpoint: `${ORDER_ENUMS_LIST_API}?include_archived=true`,
      });
      const rows = normalizeRows(response);
      const nextStats: Record<string, EnumUsageStats> = {};
      rows.forEach(row => {
        const stats = getEnumStats(row);
        if (stats) nextStats[row.enum_id] = stats;
      });
      setEnums(rows.map(transformApiEnum));
      setStatsMap(nextStats);
    } catch (error) {
      if (!(error instanceof MissingApiKeyError)) {
        showToast(
          error instanceof Error ? error.message : "Failed to load order tags",
          "error"
        );
      }
      setEnums([]);
      setStatsMap({});
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refresh();
    async function loadSymbols() {
      setSymbolsLoading(true);
      try {
        const rows = await fetchPublicFutures();
        setAvailableSymbols(rows.map(row => row.symbol).filter(Boolean));
      } catch {
        setAvailableSymbols([]);
      } finally {
        setSymbolsLoading(false);
      }
    }
    loadSymbols();
  }, [refresh]);

  const activeEnums = useMemo(
    () => enums.filter(item => item.status === "active"),
    [enums]
  );
  const archivedEnums = useMemo(
    () => enums.filter(item => item.status === "archived"),
    [enums]
  );
  const existingEnumIds = useMemo(
    () => enums.map(item => item.enum_id),
    [enums]
  );

  function showToast(message: string, type: "success" | "error" = "success") {
    setToast({ message, type });
    window.setTimeout(() => setToast(null), 3500);
  }

  function openCreateDialog() {
    setEditEnum(null);
    setDialogOpen(true);
  }

  async function handleArchiveConfirm() {
    if (!archiveTarget) return;
    try {
      await signedAdminRequest<OrderEnumMutationResponse>({
        endpoint: `${ORDER_ENUM_API}/${isArchiveAction ? "archive" : "unarchive"}`,
        method: "POST",
        data: { enum_id: archiveTarget.enum_id },
      });
      showToast(isArchiveAction ? "Order tag archived" : "Order tag restored");
      setArchiveTarget(null);
      await refresh();
    } catch (error) {
      showToast(
        error instanceof Error ? error.message : "Operation failed",
        "error"
      );
    }
  }

  return (
    <PageShell pageTitle="Order tags">
      <div className="space-y-6">
        <div className="flex items-start justify-between gap-4">
          <div>
            <h2 className="mb-2 text-lg font-medium text-[var(--fg-base)]">
              Customized trading fees per order
            </h2>
            <p className="text-sm text-(--fg-secondary)">
              Create order tags that apply{" "}
              <span className="font-medium text-[var(--fg-brand)]">
                additional
              </span>{" "}
              custom trading fees when passed in your DEX order flow.
            </p>
            <a
              href="https://orderly.network/docs/build-on-omnichain/user-flows/order-enum-integration-guide"
              target="_blank"
              rel="noreferrer"
              className="mt-2 inline-flex items-center gap-1 text-xs font-medium text-[var(--fg-brand)] hover:underline"
            >
              View integration guide
              <ExternalLink className="h-3.5 w-3.5" />
            </a>
          </div>
          <button
            type="button"
            onClick={openCreateDialog}
            disabled={activeEnums.length >= MAX_ACTIVE_ENUMS}
            className="inline-flex h-10 items-center gap-2 rounded-full px-4 text-sm font-semibold text-[var(--fg-base)] transition hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            style={{ background: "var(--bg-primary)" }}
          >
            <Plus className="h-4 w-4" />
            Create tag
          </button>
        </div>

        {loading && enums.length === 0 ? (
          <LoadingSkeleton />
        ) : enums.length === 0 ? (
          <EmptyState onCreate={openCreateDialog} />
        ) : (
          <EnumListSection
            activeEnums={activeEnums}
            archivedEnums={archivedEnums}
            statsMap={statsMap}
            onEdit={item => {
              setEditEnum(item);
              setDialogOpen(true);
            }}
            onArchive={item => {
              setArchiveTarget(item);
              setIsArchiveAction(true);
            }}
            onUnarchive={item => {
              setArchiveTarget(item);
              setIsArchiveAction(false);
            }}
          />
        )}
      </div>

      <OrderEnumDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        editEnum={editEnum}
        existingEnumIds={existingEnumIds}
        availableSymbols={availableSymbols}
        isLoadingSymbols={symbolsLoading}
        activeCount={activeEnums.length}
        onSuccess={async message => {
          showToast(message);
          setDialogOpen(false);
          await refresh();
        }}
      />

      <ArchiveConfirmModal
        target={archiveTarget}
        isArchive={isArchiveAction}
        onClose={() => setArchiveTarget(null)}
        onConfirm={handleArchiveConfirm}
      />

      {toast && (
        <div
          className={`fixed bottom-6 right-6 z-[100] rounded-xl border px-4 py-3 text-sm shadow-xl ${toast.type === "success" ? "border-[var(--border-positive)] bg-[var(--bg-positive-subtle)] text-[var(--fg-base)]" : "border-[var(--border-negative)] bg-[var(--bg-negative-subtle)] text-[var(--fg-base)]"}`}
        >
          {toast.message}
        </div>
      )}
    </PageShell>
  );
}

function EnumListSection({
  activeEnums,
  archivedEnums,
  statsMap,
  onEdit,
  onArchive,
  onUnarchive,
}: {
  activeEnums: OrderEnum[];
  archivedEnums: OrderEnum[];
  statsMap: Record<string, EnumUsageStats>;
  onEdit: (item: OrderEnum) => void;
  onArchive: (item: OrderEnum) => void;
  onUnarchive: (item: OrderEnum) => void;
}) {
  return (
    <div className="space-y-8">
      <section className="space-y-4">
        <h3 className="text-sm font-medium text-[var(--fg-base)]">
          Active ({activeEnums.length}/{MAX_ACTIVE_ENUMS})
        </h3>
        {activeEnums.length === 0 ? (
          <div className="py-4 text-sm text-(--fg-placeholder)">
            No active order tags
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-4 lg:grid-cols-2 xl:grid-cols-3">
            {activeEnums.map(item => (
              <EnumCard
                key={item.enum_id}
                enumItem={item}
                stats={statsMap[item.enum_id]}
                onEdit={onEdit}
                onArchive={onArchive}
              />
            ))}
          </div>
        )}
      </section>

      {archivedEnums.length > 0 && (
        <section className="space-y-4">
          <h3 className="text-sm font-medium text-[var(--fg-base)]">
            Archived ({archivedEnums.length})
          </h3>
          <div className="grid grid-cols-1 gap-4 lg:grid-cols-2 xl:grid-cols-3">
            {archivedEnums.map(item => (
              <EnumCard
                key={item.enum_id}
                enumItem={item}
                stats={statsMap[item.enum_id]}
                onEdit={onEdit}
                onUnarchive={onUnarchive}
                isArchived
              />
            ))}
          </div>
        </section>
      )}
    </div>
  );
}

function EnumCard({
  enumItem,
  stats,
  onEdit,
  onArchive,
  onUnarchive,
  isArchived,
}: {
  enumItem: OrderEnum;
  stats?: EnumUsageStats;
  onEdit: (item: OrderEnum) => void;
  onArchive?: (item: OrderEnum) => void;
  onUnarchive?: (item: OrderEnum) => void;
  isArchived?: boolean;
}) {
  const [copied, setCopied] = useState(false);
  const [overrideOpen, setOverrideOpen] = useState(false);
  const copyResetTimer = useRef<number | null>(null);
  const overrideEntries = Object.entries(enumItem.pair_overrides || {});

  useEffect(
    () => () => {
      if (copyResetTimer.current) window.clearTimeout(copyResetTimer.current);
    },
    []
  );

  async function handleCopyTag() {
    await copyText(`enum:${enumItem.enum_id}`);
    setCopied(true);
    if (copyResetTimer.current) window.clearTimeout(copyResetTimer.current);
    copyResetTimer.current = window.setTimeout(() => setCopied(false), 2000);
  }

  return (
    <div
      className={`h-full min-w-0 rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] p-5 ${isArchived ? "opacity-70" : ""}`}
    >
      <div className="mb-3 flex items-start justify-between gap-3">
        <div className="min-w-0">
          <div className="flex items-center gap-2">
            <span className="truncate text-sm font-medium text-[var(--fg-base)]">
              {enumItem.name}
            </span>
            <StatusBadge status={enumItem.status} />
          </div>
          <div className="mt-1 flex items-center gap-1.5 text-xs text-(--fg-placeholder)">
            <span className="truncate">enum:{enumItem.enum_id}</span>
            <button
              type="button"
              onClick={handleCopyTag}
              className="transition-colors hover:text-[var(--fg-base)]"
              aria-label="Copy order tag"
            >
              {copied ? (
                <Check className="h-3.5 w-3.5 text-[var(--fg-brand)]" />
              ) : (
                <Copy className="h-3.5 w-3.5" />
              )}
            </button>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button
            type="button"
            onClick={() => onEdit(enumItem)}
            className="p-2 text-[var(--fg-placeholder)] transition-colors hover:text-[var(--fg-base)]"
          >
            <Pencil className="h-4 w-4" />
          </button>
          {isArchived
            ? onUnarchive && (
                <button
                  type="button"
                  onClick={() => onUnarchive(enumItem)}
                  className="p-2 text-[var(--fg-placeholder)] transition-colors hover:text-[var(--fg-brand)]"
                >
                  <RotateCcw className="h-4 w-4" />
                </button>
              )
            : onArchive && (
                <button
                  type="button"
                  onClick={() => onArchive(enumItem)}
                  className="p-2 text-[var(--fg-placeholder)] transition-colors hover:text-[var(--fg-negative)]"
                >
                  <Archive className="h-4 w-4" />
                </button>
              )}
        </div>
      </div>

      {enumItem.description && (
        <p className="mb-3 text-xs leading-relaxed text-[var(--fg-placeholder)]">
          {enumItem.description}
        </p>
      )}
      <div className="mb-3 h-px bg-[var(--border-subtle)]" />

      <div className="mb-3 grid grid-cols-2 gap-4">
        <Metric
          label="Default fee"
          value={formatFeeRate(enumItem.default_fee_rate)}
        />
        {stats && (
          <>
            <Metric label="Orders" value={formatNumber(stats.orders_count)} />
            <Metric label="Volume" value={formatCurrency(stats.volume_usd)} />
            <Metric
              label="Fees"
              value={formatCurrency(stats.fees_collected_usd)}
            />
          </>
        )}
      </div>

      {overrideEntries.length > 0 && (
        <button
          type="button"
          onClick={() => setOverrideOpen(true)}
          className="rounded-full bg-[var(--bg-surface-secondary)] px-2.5 py-1 text-xs font-medium text-[var(--fg-secondary)] transition-colors hover:text-[var(--fg-base)]"
        >
          {overrideEntries.length} symbol-specific fee
          {overrideEntries.length > 1 ? "s" : ""}
        </button>
      )}

      <OverridePairsModal
        open={overrideOpen}
        onClose={() => setOverrideOpen(false)}
        enumItem={enumItem}
        entries={overrideEntries}
      />
    </div>
  );
}

function Metric({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <div className="text-xs text-[var(--fg-placeholder)]">{label}</div>
      <div className="text-sm font-medium text-[var(--fg-base)]">{value}</div>
    </div>
  );
}

function StatusBadge({ status }: { status: OrderEnumStatus }) {
  return status === "active" ? (
    <span className="rounded-full bg-[var(--bg-primary-subtle)] px-2.5 py-0.5 text-[10px] font-medium text-[var(--fg-brand)]">
      Active
    </span>
  ) : (
    <span className="rounded-full bg-[var(--bg-hover)] px-2.5 py-0.5 text-[10px] font-medium text-[var(--fg-placeholder)]">
      Archived
    </span>
  );
}

function OrderEnumDialog({
  open,
  onOpenChange,
  editEnum,
  existingEnumIds,
  availableSymbols,
  isLoadingSymbols,
  activeCount,
  onSuccess,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  editEnum: OrderEnum | null;
  existingEnumIds: string[];
  availableSymbols: string[];
  isLoadingSymbols: boolean;
  activeCount: number;
  onSuccess: (message: string) => void | Promise<void>;
}) {
  const isEdit = Boolean(editEnum);
  const [enumId, setEnumId] = useState("");
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [feeRate, setFeeRate] = useState("");
  const [pairOverrides, setPairOverrides] = useState<Record<string, string>>(
    {}
  );
  const [selectedSymbol, setSelectedSymbol] = useState("");
  const [overrideRate, setOverrideRate] = useState("");
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (editEnum) {
      setEnumId(editEnum.enum_id);
      setName(editEnum.name);
      setDescription(editEnum.description || "");
      setFeeRate((editEnum.default_fee_rate * 100).toString());
      setPairOverrides(
        Object.fromEntries(
          Object.entries(editEnum.pair_overrides || {}).map(
            ([symbol, rate]) => [symbol, (rate * 100).toString()]
          )
        )
      );
    } else {
      setEnumId("");
      setName("");
      setDescription("");
      setFeeRate("");
      setPairOverrides({});
    }
    setSelectedSymbol("");
    setOverrideRate("");
    setErrors({});
  }, [editEnum, open]);

  const filteredSymbols = availableSymbols.filter(
    symbol => !Object.keys(pairOverrides).includes(symbol)
  );

  function addPairOverride() {
    if (!selectedSymbol || !overrideRate) return;
    const decimal = parsePercentInput(overrideRate);
    const error = validatePairOverride(decimal);
    if (error) {
      setErrors(prev => ({ ...prev, general: error }));
      return;
    }
    setPairOverrides(prev => ({ ...prev, [selectedSymbol]: overrideRate }));
    setSelectedSymbol("");
    setOverrideRate("");
  }

  function validate(): boolean {
    const next: Record<string, string> = {};
    if (!isEdit) {
      const idError = validateEnumId(enumId);
      if (idError) next.enumId = idError;
      if (existingEnumIds.includes(enumId))
        next.enumId = "Tag ID already exists";
      if (activeCount >= MAX_ACTIVE_ENUMS)
        next.general = `Maximum ${MAX_ACTIVE_ENUMS} active enums allowed`;
    }
    if (!name.trim()) next.name = "Name is required";
    const feeError = validateFeeRate(parsePercentInput(feeRate));
    if (feeError) next.feeRate = feeError;
    Object.entries(pairOverrides).forEach(([symbol, rate]) => {
      const overrideError = validatePairOverride(parsePercentInput(rate));
      if (overrideError)
        next[`override_${symbol}`] = `${symbol}: ${overrideError}`;
    });
    setErrors(next);
    return Object.keys(next).length === 0;
  }

  async function handleSubmit() {
    if (!validate()) return;
    setSubmitting(true);
    try {
      const overrides = Object.fromEntries(
        Object.entries(pairOverrides).map(([symbol, rate]) => [
          symbol,
          parsePercentInput(rate),
        ])
      );
      const payload = {
        name: name.trim(),
        description: description.trim(),
        default_fee_rate: parsePercentInput(feeRate),
        pair_overrides: overrides,
      };
      const response = await signedAdminRequest<OrderEnumMutationResponse>({
        endpoint: isEdit
          ? `${ORDER_ENUM_API}/${editEnum?.enum_id}`
          : ORDER_ENUM_API,
        method: isEdit ? "PUT" : "POST",
        data: isEdit ? payload : { enum_id: enumId, ...payload },
      });
      if (response.success === false)
        throw new Error(response.message || "Operation failed");
      await onSuccess(isEdit ? "Order tag updated" : "Order tag created");
    } catch (error) {
      setErrors({
        general: error instanceof Error ? error.message : "Operation failed",
      });
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <Modal
      open={open}
      title={isEdit ? "Edit order tag" : "Create order tag"}
      onClose={() => onOpenChange(false)}
    >
      <div className="space-y-5">
        {!isEdit && (
          <div className="flex items-start gap-2 rounded-xl bg-(--bg-surface-secondary) px-3 py-2.5 text-xs text-(--fg-secondary)">
            <Info className="mt-0.5 h-4 w-4 shrink-0 text-[var(--fg-brand)]" />
            Create an order tag to assign differentiated fees. Format: UPPERCASE
            letters, numbers, and underscores only (e.g., STRATEGY_DCA).
          </div>
        )}
        {!isEdit && (
          <TextField
            label="Tag ID"
            value={enumId}
            onChange={value => setEnumId(value.toUpperCase())}
            error={errors.enumId}
            placeholder="STRATEGY_DCA"
            helperText="Max 31 chars, UPPERCASE, alphanumeric + underscore"
          />
        )}
        <TextField
          label="Name"
          value={name}
          onChange={setName}
          error={errors.name}
          placeholder="Strategy name"
          required
        />
        <TextField
          label="Description"
          value={description}
          onChange={setDescription}
          placeholder="Optional description"
        />
        <TextField
          label="Default fee rate"
          value={feeRate}
          onChange={value => setFeeRate(sanitizePercentInput(value))}
          error={errors.feeRate}
          placeholder="0.5"
          suffix="%"
          helperText="Range: 0.001% - 1.000% (input as percentage, e.g. 0.5 for 0.5%)"
          required
        />

        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <span className="text-sm text-(--fg-secondary)">
              Pair overrides
            </span>
            <span className="text-xs text-(--fg-placeholder)">Optional</span>
          </div>
          {Object.entries(pairOverrides).map(([symbol, rate]) => (
            <div key={symbol} className="flex items-center gap-2">
              <div className="flex h-11 flex-1 items-center justify-between rounded-lg border border-[var(--border-subtle)] bg-[var(--bg-secondary)] px-3 transition-colors focus-within:border-[var(--border-primary)]">
                <span className="text-sm font-medium text-[var(--fg-base)]">
                  {symbol}
                </span>
                <div className="flex items-center gap-2">
                  <input
                    value={rate}
                    onChange={event =>
                      setPairOverrides(prev => ({
                        ...prev,
                        [symbol]: sanitizePercentInput(event.target.value),
                      }))
                    }
                    className="w-20 bg-transparent text-right text-sm text-[var(--fg-base)] outline-none placeholder:text-[var(--fg-placeholder)]"
                  />
                  <span className="text-sm text-(--fg-placeholder)">%</span>
                </div>
              </div>
              <button
                type="button"
                onClick={() =>
                  setPairOverrides(prev => {
                    const next = { ...prev };
                    delete next[symbol];
                    return next;
                  })
                }
                className="p-2 text-[var(--fg-placeholder)] hover:text-[var(--fg-negative)]"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
          ))}
          <div className="flex items-center gap-2">
            <select
              value={selectedSymbol}
              onChange={event => setSelectedSymbol(event.target.value)}
              className="h-11 flex-1 rounded-lg border border-[var(--border-subtle)] bg-[var(--bg-secondary)] px-3 text-base text-[var(--fg-base)] outline-none transition-colors focus:border-[var(--border-primary)] sm:text-sm"
            >
              <option value="">
                {isLoadingSymbols ? "Loading symbols..." : "Select symbol..."}
              </option>
              {filteredSymbols.map(symbol => (
                <option key={symbol} value={symbol}>
                  {symbol}
                </option>
              ))}
            </select>
            <div className="flex h-11 w-28 items-center rounded-lg border border-[var(--border-subtle)] bg-[var(--bg-secondary)] px-3 transition-colors focus-within:border-[var(--border-primary)]">
              <input
                value={overrideRate}
                onChange={event =>
                  setOverrideRate(sanitizePercentInput(event.target.value))
                }
                placeholder="0.3"
                className="w-full bg-transparent text-right text-sm text-[var(--fg-base)] outline-none placeholder:text-[var(--fg-placeholder)]"
              />
              <span className="ml-1 text-sm text-(--fg-placeholder)">%</span>
            </div>
            <button
              type="button"
              onClick={addPairOverride}
              disabled={!selectedSymbol || !overrideRate}
              className="h-11 rounded-xl px-4 text-sm font-medium text-[var(--fg-base)] disabled:opacity-40"
              style={{ background: "var(--bg-primary)" }}
            >
              Add
            </button>
          </div>
        </div>

        {Object.entries(errors).map(
          ([key, value]) =>
            key.startsWith("override_") && (
              <p key={key} className="text-xs text-[var(--fg-negative)]">
                {value}
              </p>
            )
        )}
        {errors.general && (
          <div className="flex items-center gap-2 rounded-xl border border-[var(--border-negative)] bg-[var(--bg-negative-subtle)] px-3 py-2 text-sm text-[var(--fg-negative)]">
            <AlertTriangle className="h-4 w-4" />
            {errors.general}
          </div>
        )}
        <div className="flex justify-end gap-3 pt-2">
          <button
            type="button"
            onClick={() => onOpenChange(false)}
            className="rounded-full border border-[var(--border-subtle)] px-4 py-2 text-sm text-[var(--fg-secondary)]"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={handleSubmit}
            disabled={submitting}
            className="rounded-full px-4 py-2 text-sm font-semibold text-[var(--fg-base)] disabled:opacity-50"
            style={{ background: "var(--bg-primary)" }}
          >
            {isEdit ? "Save" : "Create"}
          </button>
        </div>
      </div>
    </Modal>
  );
}

function TextField({
  label,
  value,
  onChange,
  error,
  placeholder,
  helperText,
  suffix,
  required,
}: {
  label: string;
  value: string;
  onChange: (value: string) => void;
  error?: string;
  placeholder?: string;
  helperText?: string;
  suffix?: string;
  required?: boolean;
}) {
  return (
    <div className="space-y-1.5">
      <label className="text-sm text-(--fg-secondary)">
        {label}
        {required && <span className="text-[var(--fg-negative)]"> *</span>}
      </label>
      <div className="flex h-11 items-center rounded-lg border border-[var(--border-subtle)] bg-[var(--bg-secondary)] px-3 transition-colors focus-within:border-[var(--border-primary)]">
        <input
          value={value}
          onChange={event => onChange(event.target.value)}
          placeholder={placeholder}
          className="w-full bg-transparent text-sm text-[var(--fg-base)] outline-none placeholder:text-[var(--fg-placeholder)]"
        />
        {suffix && (
          <span className="text-sm text-(--fg-placeholder)">{suffix}</span>
        )}
      </div>
      {error ? (
        <p className="text-xs text-[var(--fg-negative)]">{error}</p>
      ) : helperText ? (
        <p className="text-xs text-(--fg-placeholder)">{helperText}</p>
      ) : null}
    </div>
  );
}

function OverridePairsModal({
  open,
  onClose,
  enumItem,
  entries,
}: {
  open: boolean;
  onClose: () => void;
  enumItem: OrderEnum;
  entries: [string, number][];
}) {
  return (
    <Modal
      open={open}
      title={`Symbol-specific fees for ${enumItem.name}`}
      onClose={onClose}
    >
      <div className="space-y-5">
        <div className="rounded-xl bg-(--bg-surface-secondary) p-4">
          <div className="flex items-start justify-between gap-6">
            <div className="min-w-0 flex-1">
              <div className="text-xs font-medium uppercase tracking-wide text-(--fg-placeholder)">
                Order tag
              </div>
              <div className="mt-1 truncate text-sm font-medium text-[var(--fg-base)]">
                enum:{enumItem.enum_id}
              </div>
            </div>
            <div className="shrink-0 border-l border-[var(--border-subtle)] pl-6 text-right">
              <div className="text-xs font-medium uppercase tracking-wide text-(--fg-placeholder)">
                Default fee
              </div>
              <div className="mt-1 text-sm font-medium text-[var(--fg-base)]">
                {formatFeeRate(enumItem.default_fee_rate)}
              </div>
            </div>
          </div>
          <p className="mt-3 text-xs leading-relaxed text-(--fg-secondary)">
            This tag uses the default fee for every symbol except the symbols
            listed below.
          </p>
        </div>
        <div className="overflow-hidden rounded-xl border border-[var(--border-subtle)]">
          <div className="grid grid-cols-[1fr_auto] gap-x-4 bg-(--bg-surface-secondary) px-4 py-2 text-xs font-medium text-(--fg-placeholder)">
            <span>Symbol</span>
            <span>Symbol-specific fee</span>
          </div>
          {entries.map(([symbol, rate]) => (
            <div
              key={symbol}
              className="grid grid-cols-[1fr_auto] items-center gap-x-4 border-t border-[var(--border-subtle)] px-4 py-3"
            >
              <span className="truncate text-xs font-medium text-[var(--fg-base)]">
                {symbol}
              </span>
              <span className="text-xs font-medium text-[var(--fg-brand)]">
                {formatFeeRate(rate)}
              </span>
            </div>
          ))}
        </div>
      </div>
    </Modal>
  );
}

function ArchiveConfirmModal({
  target,
  isArchive,
  onClose,
  onConfirm,
}: {
  target: OrderEnum | null;
  isArchive: boolean;
  onClose: () => void;
  onConfirm: () => void;
}) {
  return (
    <Modal
      open={Boolean(target)}
      title={isArchive ? "Archive order tag" : "Restore order tag"}
      onClose={onClose}
    >
      {target && (
        <div className="space-y-4">
          <div className="rounded-xl bg-(--bg-surface-secondary) p-4">
            <div className="text-xs font-medium uppercase tracking-wide text-(--fg-placeholder)">
              Order tag
            </div>
            <div className="mt-1 truncate text-sm font-medium text-[var(--fg-base)]">
              {target.name}
            </div>
            <div className="mt-1 truncate text-xs text-(--fg-secondary)">
              enum:{target.enum_id}
            </div>
          </div>
          {isArchive && (
            <div className="flex items-start gap-3 rounded-xl border border-[var(--border-negative)] bg-[var(--bg-negative-subtle)] p-4">
              <AlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-[var(--fg-negative)]" />
              <div className="space-y-1">
                <p className="text-sm font-medium text-[var(--fg-base)]">
                  This prevents new usage
                </p>
                <p className="text-xs leading-relaxed text-(--fg-secondary)">
                  Archived tags cannot be applied to new orders. Existing orders
                  continue processing, but this tag will no longer apply
                  additional custom fees. Archived tags are purged after 30
                  days.
                </p>
              </div>
            </div>
          )}
          <p className="text-sm text-(--fg-secondary)">
            {isArchive
              ? "Archive this order tag? You can restore it within 30 days if you need to use it again."
              : "Restore this order tag? It will be available for new orders again."}
          </p>
          <div className="flex justify-end gap-3">
            <button
              type="button"
              onClick={onClose}
              className="rounded-full border border-[var(--border-subtle)] px-4 py-2 text-sm text-[var(--fg-secondary)]"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={onConfirm}
              className="rounded-full px-4 py-2 text-sm font-semibold text-[var(--fg-base)]"
              style={{ background: "var(--bg-primary)" }}
            >
              {isArchive ? "Archive" : "Restore"}
            </button>
          </div>
        </div>
      )}
    </Modal>
  );
}

function EmptyState({ onCreate }: { onCreate: () => void }) {
  return (
    <div className="flex flex-col items-center justify-center gap-4 rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] px-4 py-16 text-center">
      <p className="text-sm font-medium text-[var(--fg-base)]">
        No order tag created yet
      </p>
      <p className="max-w-[460px] text-sm leading-snug text-(--fg-secondary)">
        Create your first order tag to customize differentiated fees on top of
        existing trading fee markups. Note that you will need to implement the
        order tag into your DEX workflow yourself.
      </p>
      <button
        type="button"
        onClick={onCreate}
        className="rounded-full px-5 py-2 text-sm font-semibold text-[var(--fg-base)]"
        style={{ background: "var(--bg-primary)" }}
      >
        Create tag
      </button>
    </div>
  );
}

